@Component
class SamlAuthenticationFilter extends OncePerRequestFilter {
    private final SamlService samlService;

    SamlAuthenticationFilter(SamlService samlService) {
        this.samlService = samlService;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, java.io.IOException {
        if (request.getRequestURI().equals("/saml/acs") && "POST".equalsIgnoreCase(request.getMethod())) {
            try {
                Authentication auth = samlService.processAcs(request);
                SecurityContextHolder.getContext().setAuthentication(auth);
                response.sendRedirect("/");
                return;
            } catch (Exception e) {
                response.sendError(401, "Invalid SAML Response");
                return;
            }
        }
        filterChain.doFilter(request, response);
    }
}

@Component
class SamlService {
    private final SamlProperties props;

    SamlService(SamlProperties props) {
        this.props = props;
    }

    public void initiateLogin(HttpServletResponse response, HttpServletRequest request) throws Exception {
        AuthnRequest authnRequest = buildAuthnRequest();
        String xml = SamlXml.toXml(authnRequest);
        String relayState = Optional.ofNullable(request.getParameter("relayState")).orElse("/");
        String redirectUrl = buildRedirectUrl(xml, relayState);
        response.sendRedirect(redirectUrl);
    }

    public Authentication processAcs(HttpServletRequest request) throws Exception {
        String samlResponseB64 = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponseB64)) throw new IllegalArgumentException("Missing SAMLResponse");
        String xml = new String(Base64.getDecoder().decode(samlResponseB64), StandardCharsets.UTF_8);
        Response response = (Response) SamlXml.fromXml(xml, Response.DEFAULT_ELEMENT_NAME);
        if (response.getAssertions().isEmpty()) throw new IllegalArgumentException("No assertions");
        Assertion assertion = response.getAssertions().get(0);
        Subject subject = assertion.getSubject();
        String nameId = subject != null && subject.getNameID() != null ? subject.getNameID().getValue() : "unknown";
        List<SimpleGrantedAuthority> authorities = List.of(new SimpleGrantedAuthority("ROLE_USER"));
        return new UsernamePasswordAuthenticationToken(nameId, "N/A", authorities);
    }

    public String metadata() throws Exception {
        EntityDescriptor entityDescriptor = buildMetadata();
        return SamlXml.toXml(entityDescriptor);
    }

    private AuthnRequest buildAuthnRequest() {
        AuthnRequest request = new AuthnRequestBuilder().buildObject();
        request.setID("_" + UUID.randomUUID());
        request.setIssueInstant(Instant.now());
        request.setVersion(SAMLVersion.VERSION_20);
        request.setDestination(props.idpSsoUrl);
        request.setAssertionConsumerServiceURL(props.acsUrl);
        request.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(props.entityId);
        request.setIssuer(issuer);
        NameIDPolicy policy = new NameIDPolicyBuilder().buildObject();
        policy.setAllowCreate(true);
        policy.setFormat(NameIDType.EMAIL);
        request.setNameIDPolicy(policy);
        return request;
    }

    private String buildRedirectUrl(String xml, String relayState) throws Exception {
        String deflated = deflate(xml.getBytes(StandardCharsets.UTF_8));
        String encoded = Base64.getEncoder().encodeToString(deflated.getBytes(StandardCharsets.ISO_8859_1));
        return UriComponentsBuilder.fromHttpUrl(props.idpSsoUrl)
                .queryParam("SAMLRequest", encoded)
                .queryParam("RelayState", relayState)
                .build(true)
                .toUriString();
    }

    private EntityDescriptor buildMetadata() {
        EntityDescriptor ed = new EntityDescriptorBuilder().buildObject();
        ed.setEntityID(props.entityId);
        SPSSODescriptor sp = new SPSSODescriptorBuilder().buildObject();
        sp.addSupportedProtocol(SAMLConstants.SAML20P_NS);
        KeyDescriptor kd = new KeyDescriptorBuilder().buildObject();
        kd.setUse(UsageType.SIGNING);
        sp.getKeyDescriptors().add(kd);
        AssertionConsumerService acs = new AssertionConsumerServiceBuilder().buildObject();
        acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acs.setLocation(props.acsUrl);
        acs.setIndex(0);
        acs.setIsDefault(true);
        sp.getAssertionConsumerServices().add(acs);
        SingleLogoutService slo = new SingleLogoutServiceBuilder().buildObject();
        slo.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
        slo.setLocation(props.sloUrl);
        sp.getSingleLogoutServices().add(slo);
        ed.getRoleDescriptors().add(sp);
        return ed;
    }

    private String deflate(byte[] data) throws Exception {
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        deflater.setInput(data);
        deflater.finish();
        byte[] buffer = new byte[4096];
        StringBuilder sb = new StringBuilder();
        while (!deflater.finished()) {
            int count = deflater.deflate(buffer);
            sb.append(new String(buffer, 0, count, StandardCharsets.ISO_8859_1));
        }
        deflater.end();
        return sb.toString();
    }
}

@Controller
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/saml/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws Exception {
        samlService.initiateLogin(response, request);
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    @ResponseBody
    public String metadata() throws Exception {
        return samlService.metadata();
    }

    @PostMapping("/saml/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response, Authentication authentication) throws Exception {
        new SecurityContextLogoutHandler().logout(request, response, authentication);
        response.sendRedirect("/");
    }

    @GetMapping("/")
    @ResponseBody
    public String home(Authentication authentication) {
        return authentication == null ? "Anonymous" : "Hello " + authentication.getName();
    }
}

class SamlXml {
    static String toXml(org.opensaml.core.xml.XMLObject object) throws Exception {
        org.opensaml.core.xml.io.Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory().getMarshaller(object);
        if (marshaller == null) throw new IllegalStateException("No marshaller");
        Element element = marshaller.marshall(object);
        return org.opensaml.core.xml.util.SerializeSupport.nodeToString(element);
    }

    static org.opensaml.core.xml.XMLObject fromXml(String xml, QName rootElementName) throws Exception {
        Element element = DocumentBuilderFactory.newInstance().newDocumentBuilder()
                .parse(new InputSource(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8))))
                .getDocumentElement();
        org.opensaml.core.xml.io.Unmarshaller unmarshaller = XMLObjectProviderRegistrySupport.getUnmarshallerFactory().getUnmarshaller(element);
        if (unmarshaller == null) throw new IllegalStateException("No unmarshaller");
        return unmarshaller.unmarshall(element);
    }
}